IntVar NT  = model.intVar("NT",  1, 3);
IntVar SA  = model.intVar("SA",  1, 3);
IntVar Q   = model.intVar("Q",   1, 3);
IntVar NSW = model.intVar("NSW", 1, 3);
IntVar V   = model.intVar("V",   1, 3);
IntVar T   = model.intVar("T",   1, 3);

