var neighborsChoco = new (IntVar, IntVar)[]
{
    (WA, NT), (NT, WA), (WA, SA), (SA, WA), (NT, SA), (SA, NT),
    (NT, Q), (Q, NT), (SA, Q), (Q, SA), (Q, NSW), (NSW, Q),
    (SA, NSW), (NSW, SA), (SA, V), (V, SA), (NSW, V), (V, NSW)
};

