// Exemple resolu : Mini-Sudoku 4x4 avec contraintes globales
//   Chaque ligne, colonne, bloc 2x2 contient les chiffres 1 a 4 (allDifferent).
//   Optimum : 1 solution unique.
var model1 = new Model("Mini-Sudoku 4x4");
var grid1 = new IntVar[4, 4];

for (int i = 0; i < 4; i++)
    for (int j = 0; j < 4; j++)
        grid1[i, j] = model1.intVar($"c1_{i}_{j}", 1, 4);

for (int i = 0; i < 4; i++) {
    var row = new IntVar[4];
    var col = new IntVar[4];
    for (int j = 0; j < 4; j++) {
        row[j] = grid1[i, j];
        col[j] = grid1[j, i];
    }
    model1.allDifferent(row).post();
    model1.allDifferent(col).post();
}

for (int bi = 0; bi < 4; bi += 2)
    for (int bj = 0; bj < 4; bj += 2) {
        var block = new IntVar[4];
        int k = 0;
        for (int di = 0; di < 2; di++)
            for (int dj = 0; dj < 2; dj++)
                block[k++] = grid1[bi + di, bj + dj];
        model1.allDifferent(block).post();
    }

var sw1 = System.Diagnostics.Stopwatch.StartNew();
bool ok1 = model1.getSolver().solve();
sw1.Stop();

Console.WriteLine($"Mini-Sudoku 4x4 resolu en {sw1.ElapsedMilliseconds} ms (trouve = {ok1}) :");
if (ok1) {
    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 4; j++) Console.Write($"{grid1[i, j].getValue()} ");
        Console.WriteLine();
    }
}
Console.WriteLine("Verification : lignes/colonnes/blocs 2x2 contiennent tous 1-4");

// Exemple resolu : Cumulative 4 taches / 2 machines (capacite 2)
//   Taches : durees [3,4,2,5], consommations [1,2,1,1]
//   Optimum : makespan = 8 unites.
var model2 = new Model("Cumulative 4/2");

var durations2 = new[] { 3, 4, 2, 5 };
var heights2 = new[] { 1, 2, 1, 1 };
int capacity2 = 2;

var tasks2 = new Task[4];
var starts2 = new IntVar[4];
var ends2 = new IntVar[4];

int horizon2 = 1;
foreach (var d in durations2) horizon2 += d;

for (int i = 0; i < 4; i++) {
    starts2[i] = model2.intVar($"start2_{i}", 0, horizon2);
    ends2[i] = model2.intVar($"end2_{i}", durations2[i], horizon2);
    tasks2[i] = new Task(starts2[i], model2.intVar(durations2[i]), ends2[i]);
}

// cumulative(Task[], IntVar[] heights, IntVar capacity) -- IKVM exige des IntVar
var heights2v = new IntVar[4];
for (int i = 0; i < 4; i++) heights2v[i] = model2.intVar(heights2[i]);
var cap2v = model2.intVar(capacity2);
model2.cumulative(tasks2, heights2v, cap2v).post();

var makespan2 = model2.intVar("makespan2", 0, horizon2);
foreach (var e in ends2) model2.arithm(makespan2, ">=", e).post();
model2.setObjective(false, makespan2);

var sw2 = System.Diagnostics.Stopwatch.StartNew();
var solver2 = model2.getSolver();
int bestMakespan2 = int.MaxValue;
while (solver2.solve()) bestMakespan2 = makespan2.getValue();
sw2.Stop();

Console.WriteLine($"Cumulative 4/2 resolu en {sw2.ElapsedMilliseconds} ms - makespan = {bestMakespan2}");
Console.WriteLine("Optimum identique version Python (cf. CSP-3-Advanced.ipynb cellule 8)");

// Exemple resolu : TSP 5 villes (cycle hamiltonien de cout minimal)
//   Distances symetriques (matrice 5x5)
//   Optimum : cout = 18 (plusieurs tours equivalents, ex 0 -> 1 -> 3 -> 4 -> 2 -> 0)
var model3 = new Model("TSP 5 villes");

var dist3 = new[,] {
    {0, 3, 1, 5, 8},
    {3, 0, 6, 2, 7},
    {1, 6, 0, 4, 9},
    {5, 2, 4, 0, 3},
    {8, 7, 9, 3, 0}
};
int n3 = 5;

var succ3 = new IntVar[n3];
for (int i = 0; i < n3; i++)
    succ3[i] = model3.intVar($"succ3_{i}", 0, n3 - 1);

model3.circuit(succ3).post();

var totalCost3 = model3.intVar("cost3", 0, 1000);
var terms3 = new IntVar[n3];
for (int i = 0; i < n3; i++) {
    terms3[i] = model3.intVar($"arc3_{i}", 0, 100);
    var row3 = new int[n3];
    for (int j = 0; j < n3; j++) row3[j] = dist3[i, j];
    model3.element(terms3[i], row3, succ3[i]).post();
}
model3.sum(terms3, "=", totalCost3).post();
model3.setObjective(false, totalCost3);

var sw3 = System.Diagnostics.Stopwatch.StartNew();
var solver3 = model3.getSolver();
int bestCost3 = int.MaxValue; int[] bestSucc3 = new int[n3];
while (solver3.solve()) {
    bestCost3 = totalCost3.getValue();
    for (int i = 0; i < n3; i++) bestSucc3[i] = succ3[i].getValue();
}
sw3.Stop();

var tour3 = new int[n3 + 1];
tour3[0] = 0;
for (int i = 1; i <= n3; i++) tour3[i] = bestSucc3[tour3[i - 1]];

Console.WriteLine($"TSP 5 villes resolu en {sw3.ElapsedMilliseconds} ms - cout = {bestCost3}");
Console.WriteLine($"Tour : {string.Join(" -> ", tour3)}");
Console.WriteLine("Optimum : 18 (plusieurs tours equivalents de cout 18).");

// Exemple resolu : Table extensionnelle - compatibilite composants
