// Large Neighborhood Search (LNS) - concept illutre sur TSP 5 villes.
// Note pedagogique : l'API LNS native Choco (solver.setLNS(...) + strategie LNS) est avancee.
// On illustre ici le PRINCIPE du LNS via l'API de base solve(), stable via le bridge IKVM.
var model5 = new Model("TSP 5 villes + LNS (concept)");

var dist5 = new[,] {
    {0, 3, 1, 5, 8},
    {3, 0, 6, 2, 7},
    {1, 6, 0, 4, 9},
    {5, 2, 4, 0, 3},
    {8, 7, 9, 3, 0}
};
int n5 = 5;

var succ5 = new IntVar[n5];
for (int i = 0; i < n5; i++) succ5[i] = model5.intVar($"succ5_{i}", 0, n5 - 1);
model5.circuit(succ5).post();

var totalCost5 = model5.intVar("cost5", 0, 1000);
var terms5 = new IntVar[n5];
for (int i = 0; i < n5; i++) {
    terms5[i] = model5.intVar($"arc5_{i}", 0, 100);
    var row5 = new int[n5];
    for (int j = 0; j < n5; j++) row5[j] = dist5[i, j];
    model5.element(terms5[i], row5, succ5[i]).post();
}
model5.sum(terms5, "=", totalCost5).post();
model5.setObjective(false, totalCost5);

var sw5 = System.Diagnostics.Stopwatch.StartNew();
var solver5 = model5.getSolver();
int bestCost5 = int.MaxValue; int[] bestSucc5 = new int[n5];
while (solver5.solve()) {
    bestCost5 = totalCost5.getValue();
    for (int i = 0; i < n5; i++) bestSucc5[i] = succ5[i].getValue();
}
sw5.Stop();

// Reconstruction du tour depuis les successeurs
var tour5 = new System.Collections.Generic.List<int>();
int cur5 = 0;
for (int i = 0; i < n5; i++) { tour5.Add(cur5); cur5 = bestSucc5[cur5]; }
tour5.Add(0);

Console.WriteLine($"LNS it 0 (optimum global) : cout = {bestCost5}");
