#r "org.chocosolver.solver.dll"

using org.chocosolver.solver;
using org.chocosolver.solver.variables;
using org.chocosolver.solver.constraints;
using org.chocosolver.solver.search.strategy.selectors.variables;
using org.chocosolver.solver.search.strategy.selectors.values;
using System;
using System.Linq;
using System.Collections.Generic;

// Désambiguïsation Task :
using Task = System.Threading.Tasks.Task;

Console.WriteLine("Choco-solver via IKVM 8.15.0 - Prêt pour optimisation combinatoire");

// Exemple resolu : Bin Packing 5 objets, capacite 10
//   Tailles : [2, 5, 4, 7, 2]  (somme = 20)
//   Borne inferieure : ceil(20/10) = 2 bins. Mais 2 bins est INFAISABLE :
//   le 7 ne peut partager avec un 4 (7+4=11>10) ni un 5 (7+5=12>10) ; reste 7+2=9,
//   et les 3 autres objets {2,4,5}=11>10 ne tiennent pas dans le second bin.
//   Optimum reel : 3 bins (ex. {7,2}=9, {5,4}=9, {2}=2).
int[] sizes = { 2, 5, 4, 7, 2 };
int nItems = sizes.Length;
int capacity = 10;
int nBins = nItems; // majorant : chaque objet dans son propre bin

var modelBp = new Model("BinPacking via Choco");
var binOf = new IntVar[nItems];
var loads = new IntVar[nBins];
for (int i = 0; i < nItems; i++)
    binOf[i] = modelBp.intVar($"b_{i}", 0, nBins - 1, false);
for (int j = 0; j < nBins; j++)
    loads[j] = modelBp.intVar($"load_{j}", 0, capacity, false);

// bEqJ[i,j] = 1 ssi objet i dans bin j (reification iff -- Choco n'a pas .imp() sur Constraint)
var bEqJ = new BoolVar[nItems, nBins];
for (int i = 0; i < nItems; i++)
    for (int j = 0; j < nBins; j++)
        bEqJ[i, j] = modelBp.boolVar($"eq_{i}_{j}");

for (int i = 0; i < nItems; i++)
    for (int j = 0; j < nBins; j++)
        modelBp.arithm(binOf[i], "=", j).reifyWith(bEqJ[i, j]);

// Charge du bin j = somme des tailles * bEqJ[i][j]
for (int j = 0; j < nBins; j++)
{
    var binVars = new IntVar[nItems];
    for (int i = 0; i < nItems; i++)
        binVars[i] = bEqJ[i, j];
    modelBp.scalar(binVars, sizes, "=", loads[j]).post();
}

// Symetrie brisee (compacite) : les bins utilises sont en tete.
//   Pattern Choco pour "C1 => C2" : reifier C1 puis ifThen(reif, C2).
for (int j = 0; j < nBins - 1; j++)
{
    var rj = modelBp.boolVar($"cmp_{j}");
    modelBp.arithm(loads[j], "=", 0).reifyWith(rj);
    modelBp.ifThen(rj, modelBp.arithm(loads[j + 1], "=", 0));
}

// Objectif : nombre de bins utilises
var nbUsedBins = modelBp.intVar("nb_used", 1, nBins, false);
var isBinUsed = new BoolVar[nBins];
for (int j = 0; j < nBins; j++)
{
    isBinUsed[j] = modelBp.boolVar($"used_{j}");
    modelBp.arithm(loads[j], ">", 0).reifyWith(isBinUsed[j]); // iff (couvre les 2 directions)
}
modelBp.sum(isBinUsed.Cast<IntVar>().ToArray(), "=", nbUsedBins).post();
modelBp.setObjective(false, nbUsedBins); // MINIMIZE = false (API Choco : bool maximize)

// Optimisation : boucle solve() jusqu'a l'optimum, capture de la meilleure solution
var solverBp = modelBp.getSolver();
int bestNbp = 0;
int[] bestBinOf = new int[nItems];
while (solverBp.solve())
{
    bestNbp = nbUsedBins.getValue();
    for (int i = 0; i < nItems; i++) bestBinOf[i] = binOf[i].getValue();
}

if (bestNbp > 0)
{
    Console.WriteLine($"Bin Packing : nombre optimal de bins = {bestNbp} (capacite {capacity})");
    for (int j = 0; j < nBins; j++)
    {
        var itemsInBin = new List<int>();
        for (int i = 0; i < nItems; i++)
            if (bestBinOf[i] == j) itemsInBin.Add(i);
        if (itemsInBin.Count > 0)
        {
            int ld = itemsInBin.Sum(i => sizes[i]);
            Console.WriteLine($"  Bin {j} (charge {ld}/{capacity}) : objets [{string.Join(",", itemsInBin)}] tailles [{string.Join(",", itemsInBin.Select(i => sizes[i].ToString()))}]");
        }
    }
}
else
{
    Console.WriteLine("Bin Packing : Pas de solution trouvee.");
}

// Exemple resolu : Knapsack 0/1, 5 objets, capacite 10
//   Objet 0 : poids=2,  valeur=6
//   Objet 1 : poids=3,  valeur=10
//   Objet 2 : poids=4,  valeur=12
//   Objet 3 : poids=5,  valeur=15
//   Objet 4 : poids=1,  valeur=1
//   Optimum connu : 31 (objets {0, 1, 3} : poids 2+3+5=10 <= 10, valeur 6+10+15=31)
int[] weights = { 2, 3, 4, 5, 1 };
int[] values  = { 6, 10, 12, 15, 1 };
int nObjs = weights.Length;
int cap = 10;

var modelKn = new Model("Knapsack via Choco");
var take = new BoolVar[nObjs];
for (int i = 0; i < nObjs; i++)
    take[i] = modelKn.boolVar($"take_{i}");

var totalWeight = modelKn.intVar("total_weight", 0, weights.Sum(), false);
var totalValue  = modelKn.intVar("total_value",  0, values.Sum(),  false);

modelKn.scalar(take, weights, "=", totalWeight).post();
modelKn.arithm(totalWeight, "<=", cap).post();
modelKn.scalar(take, values, "=", totalValue).post();
modelKn.setObjective(true, totalValue); // MAXIMIZE = true

// Boucle d'optimisation jusqu'a l'optimum
var solverKn = modelKn.getSolver();
int bestTv = 0, bestTw = 0;
int[] bestTake = new int[nObjs];
while (solverKn.solve())
{
    bestTv = totalValue.getValue();
    bestTw = totalWeight.getValue();
    for (int i = 0; i < nObjs; i++) bestTake[i] = take[i].getValue();
}

if (bestTv > 0)
{
    var selected = new List<int>();
    for (int i = 0; i < nObjs; i++)
        if (bestTake[i] == 1) selected.Add(i);
    Console.WriteLine($"Knapsack : valeur optimale = {bestTv} (poids {bestTw}/{cap})");
    Console.WriteLine($"  Objets selectionnes : [{string.Join(",", selected)}]");
    Console.WriteLine($"  Poids : [{string.Join(",", selected.Select(i => weights[i].ToString()))}], Valeurs : [{string.Join(",", selected.Select(i => values[i].ToString()))}]");
}
else
{
    Console.WriteLine("Knapsack : Pas de solution trouvee.");
}

// Exemple resolu : Cutting Stock, barres de longueur 10
//   Pieces : 6 de longueur 4, 4 de longueur 7, 3 de longueur 9
//   Total longueur = 6*4 + 4*7 + 3*9 = 79
//   Optimum reel : 10 barres. Decomposition (aucune combinaison inter-groupe possible,
//   car 9+*>10, 7+*>10, et seules deux 4 tiennent ensemble : 4+4=8) :
//     - 3 pieces de 9 : isolees (9+rien), 3 barres
//     - 4 pieces de 7 : isolees (7+rien), 4 barres
//     - 6 pieces de 4 : par paires (4+4=8), 3 barres
//     Total = 3+4+3 = 10 barres.
int[] pieceLengths = { 4, 4, 4, 4, 4, 4, 7, 7, 7, 7, 9, 9, 9 };
int stockLength = 10;
int nPieces = pieceLengths.Length;
int nBarsCs = nPieces; // majorant

var modelCs = new Model("CuttingStock via Choco");
var barOf = new IntVar[nPieces];
var loadsCs = new IntVar[nBarsCs];
for (int i = 0; i < nPieces; i++)
    barOf[i] = modelCs.intVar($"bar_{i}", 0, nBarsCs - 1, false);
for (int j = 0; j < nBarsCs; j++)
    loadsCs[j] = modelCs.intVar($"load_{j}", 0, stockLength, false);

// Contrainte GLOBALE binPacking : loadsCs[j] = sum(pieceLengths[i] pour barOf[i]==j).
// Signature : binPacking(itemBin, itemSize, binLoad, offset=0). Propagation native forte :
// c'est l'idiome Choco pour le Bin Packing / Cutting Stock (SOTA, cf. Prong A #3801).
modelCs.binPacking(barOf, pieceLengths, loadsCs, 0).post();  // (itemBin, itemSize, binLoad, offset)

// Capacite de chaque barre
for (int j = 0; j < nBarsCs; j++)
    modelCs.arithm(loadsCs[j], "<=", stockLength).post();

// Symetrie brisee (compacite) : barres utilisees en tete
for (int j = 0; j < nBarsCs - 1; j++)
{
    var rj = modelCs.boolVar($"cmp_{j}");
    modelCs.arithm(loadsCs[j], "=", 0).reifyWith(rj);
    modelCs.ifThen(rj, modelCs.arithm(loadsCs[j + 1], "=", 0));
}

// Objectif : nombre de barres utilisees
var nbBarsUsed = modelCs.intVar("nb_bars_used", 1, nBarsCs, false);
var barActive = new BoolVar[nBarsCs];
for (int j = 0; j < nBarsCs; j++)
{
    barActive[j] = modelCs.boolVar($"active_{j}");
    modelCs.arithm(loadsCs[j], ">", 0).reifyWith(barActive[j]); // iff
}
modelCs.sum(barActive.Cast<IntVar>().ToArray(), "=", nbBarsUsed).post();
modelCs.setObjective(false, nbBarsUsed); // MINIMIZE

var solverCs = modelCs.getSolver();
int bestNbu = 0;
int[] bestBarOf = new int[nPieces];
while (solverCs.solve())
{
    bestNbu = nbBarsUsed.getValue();
    for (int i = 0; i < nPieces; i++) bestBarOf[i] = barOf[i].getValue();
}

if (bestNbu > 0)
{
    Console.WriteLine($"Cutting Stock : nombre optimal de barres = {bestNbu} (longueur stock {stockLength})");
    for (int j = 0; j < nBarsCs; j++)
    {
        var piecesHere = new List<int>();
        for (int i = 0; i < nPieces; i++)
            if (bestBarOf[i] == j) piecesHere.Add(i);
        if (piecesHere.Count > 0)
        {
            int ld = piecesHere.Sum(i => pieceLengths[i]);
            Console.WriteLine($"  Barre {j} (longueur {ld}/{stockLength}) : pieces [{string.Join(",", piecesHere)}] longueurs [{string.Join(",", piecesHere.Select(i => pieceLengths[i].ToString()))}]");
        }
    }
}
else
{
    Console.WriteLine("Cutting Stock : Pas de solution trouvee.");
}

// Exemple resolu : Portefeuille de 5 actifs, max 3 actifs, risque borne
//   Actif 0 : rendement=5,  risque=10
//   Actif 1 : rendement=12, risque=20
//   Actif 2 : rendement=8,  risque=15
//   Actif 3 : rendement=15, risque=30
//   Actif 4 : rendement=10, risque=18
//   Max 3 actifs, risque total <= 50. Optimum : {1, 3} rendement 12+15=27, risque 20+30=50.
int[] returns   = { 5, 12, 8, 15, 10 };
int[] risks    = { 10, 20, 15, 30, 18 };
int nAssets = returns.Length;
int maxAssets = 3;
int riskCap = 50;

var modelPf = new Model("Portfolio via Choco");
var hold = new BoolVar[nAssets];
for (int i = 0; i < nAssets; i++)
    hold[i] = modelPf.boolVar($"hold_{i}");

var totalReturn = modelPf.intVar("total_return", 0, returns.Sum(), false);
var totalRisk   = modelPf.intVar("total_risk",   0, risks.Sum(),    false);
var nbHold      = modelPf.intVar("nb_hold",      0, nAssets,        false);

modelPf.scalar(hold, returns, "=", totalReturn).post();
modelPf.scalar(hold, risks,   "=", totalRisk).post();
modelPf.sum(hold.Cast<IntVar>().ToArray(), "=", nbHold).post();
modelPf.arithm(nbHold, "<=", maxAssets).post();
modelPf.arithm(totalRisk, "<=", riskCap).post();
modelPf.setObjective(true, totalReturn); // MAXIMIZE

var solverPf = modelPf.getSolver();
int bestTr = 0, bestTkr = 0;
int[] bestHold = new int[nAssets];
while (solverPf.solve())
{
    bestTr = totalReturn.getValue();
    bestTkr = totalRisk.getValue();
    for (int i = 0; i < nAssets; i++) bestHold[i] = hold[i].getValue();
}

if (bestTr > 0)
{
    var selected = new List<int>();
    for (int i = 0; i < nAssets; i++)
        if (bestHold[i] == 1) selected.Add(i);
    Console.WriteLine($"Portfolio : rendement optimal = {bestTr} (risque {bestTkr}/{riskCap}, {selected.Count}/{maxAssets} actifs)");
    Console.WriteLine($"  Actifs selectionnes : [{string.Join(",", selected)}]");
    Console.WriteLine($"  Rendements : [{string.Join(",", selected.Select(i => returns[i].ToString()))}], Risques : [{string.Join(",", selected.Select(i => risks[i].ToString()))}]");
}
else
{
    Console.WriteLine("Portfolio : Pas de solution (risque trop contraignant ?).");
}

